create table dirkspzm32.isi_currency (
    sid                  varchar2(2 char) default '01' not null enable,
    firma_nr             number(2, 0) default 1 not null enable,
    currency             varchar2(10 char) not null enable,
    valide_date          date not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0),
    bezeichnung1         varchar2(50 char),
    wechselkurs          number(*, 5),
    base_currency        varchar2(10 char)
);

alter table dirkspzm32.isi_currency
    add constraint pk_currency primary key ( currency,
                                             valide_date )
        using index enable;


